class WebSocketConnection extends EventEmitter {
  constructor(manager, gateway) {
    super();
    this.manager = manager;
    this.client = manager.client;
    this.ws = null;
    this.sequence = -1;
    this.status = Constants.Status.IDLE;
    this.packetManager = new PacketManager(this);
